INSERT INTO audit_logs (id, user_id, table_name, record_id, action, old_data, new_data, created_at) VALUES ('b6ace8ee-e5df-4b24-8f70-8392fbcfaa0c', NULL, 'products', '13ee0539-8aca-409d-841d-b156a50ea87b', 'UPDATE', '{"id": "13ee0539-8aca-409d-841d-b156a50ea87b", "sku": "DR410.0052", "price": 1.55, "title_en": null, "title_it": "New Cristal", "is_active": true, "attributes": {"ml": 0, "colore": "Oro brillante, tasto bianco", "finitura": "Metallizato", "categoria": "Dispenser", "materiale": "PP", "imboccatura": "GCMI 24/410"}, "created_at": "2026-06-16T09:25:52.692006+00:00", "image_urls": ["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/DR410.0052.jpg"], "category_id": null, "box_quantity": 1, "is_accessory": false, "description_en": "<pre data-placeholder=\"Traduzione\" dir=\"ltr\" id=\"tw-target-text\"> The New Cristal dispenser has been specially designed to be coordinated with the New Cristal bottle, adapting the lines and the design of the bottle itself, in order to give it the maximum aesthetic balance. Ideal for dispensing a wide range of cosmetic products, for cleansing and hair care.</pre>", "description_it": "<p>Il dispenser New Cristal &egrave; stato appositamente progettato per essere coordinato al flacone New Cristal, adattandolo le linee e il desing del flacone stesso, al fine di conferirgli il massimo equilibrio estetico. Ideale per l&rsquo;erogazione di un&rsquo;ampia gamma di prodotti cosmetici, per la detergenza e per la cura dei capelli.</p>", "stock_quantity": 0}', '{"id": "13ee0539-8aca-409d-841d-b156a50ea87b", "sku": "DR410.0052", "price": 1.55, "title_en": null, "title_it": "New Cristal", "is_active": true, "attributes": {"ml": 0, "colore": "Oro brillante, tasto bianco", "finitura": "Metallizato", "categoria": "Dispenser", "materiale": "PP", "imboccatura": "GCMI 24/410"}, "created_at": "2026-06-16T09:25:52.692006+00:00", "image_urls": ["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/DR410.0052.jpg"], "category_id": null, "box_quantity": 750, "is_accessory": false, "description_en": "<pre data-placeholder=\"Traduzione\" dir=\"ltr\" id=\"tw-target-text\"> The New Cristal dispenser has been specially designed to be coordinated with the New Cristal bottle, adapting the lines and the design of the bottle itself, in order to give it the maximum aesthetic balance. Ideal for dispensing a wide range of cosmetic products, for cleansing and hair care.</pre>", "description_it": "<p>Il dispenser New Cristal &egrave; stato appositamente progettato per essere coordinato al flacone New Cristal, adattandolo le linee e il desing del flacone stesso, al fine di conferirgli il massimo equilibrio estetico. Ideale per l&rsquo;erogazione di un&rsquo;ampia gamma di prodotti cosmetici, per la detergenza e per la cura dei capelli.</p>", "stock_quantity": 0}', '2026-06-18T07:15:13.516725+00:00');
